import {
    DEFAULT_NOTIFICATION_PREFERENCES,
    NOTIFICATION_CATEGORIES,
    type DbDriver,
    type NotificationCategory,
    type NotificationPayload,
    type NotificationPreferences,
    type PushSubscriptionPayload,
} from '@motivation/shared';
import { DbService } from '../db/db.service.js';
import { API_URL } from '../config.js';

const PREFERENCES_KEY = 'notifications.preferences';

const MEAL_REMINDERS: Array<{ meal: 'Lunch' | 'Dinner'; startHour: number; endHour: number }> = [
    { meal: 'Lunch', startHour: 14, endHour: 17 },
    { meal: 'Dinner', startHour: 21, endHour: 24 },
];

export interface NotificationsServiceDeps {
    driver?: () => Promise<DbDriver>;
    fetchImpl?: typeof fetch;
    notificationCtor?: typeof Notification;
    getPermission?: () => NotificationPermission;
    requestPermissionImpl?: () => Promise<NotificationPermission>;
    showNotification?: (payload: NotificationPayload) => Promise<void> | void;
    swRegistration?: () => Promise<ServiceWorkerRegistration | null>;
    now?: () => Date;
    todayIso?: () => string;
}

export interface LocalCheckResult {
    shown: NotificationPayload[];
    skipped: string[];
}

async function defaultDriver(): Promise<DbDriver> {
    const service = DbService.getInstance();
    await service.init();
    return service.driver;
}

async function defaultSwRegistration(): Promise<ServiceWorkerRegistration | null> {
    if (typeof navigator === 'undefined' || !('serviceWorker' in navigator)) return null;
    const registration = await navigator.serviceWorker.getRegistration();
    return registration ?? null;
}

function todayIsoDefault(): string {
    return new Date().toISOString().slice(0, 10);
}

function urlBase64ToUint8Array(base64String: string): Uint8Array<ArrayBuffer> {
    const padding = '='.repeat((4 - base64String.length % 4) % 4);
    const base64 = (base64String + padding).replace(/-/g, '+').replace(/_/g, '/');
    const rawData = atob(base64);
    const buffer = new ArrayBuffer(rawData.length);
    const output = new Uint8Array(buffer);
    for (let i = 0; i < rawData.length; i += 1) output[i] = rawData.charCodeAt(i);
    return output;
}

export class NotificationsService {
    private readonly deps: Required<Omit<NotificationsServiceDeps, 'notificationCtor'>> & { notificationCtor?: typeof Notification };

    constructor(deps: NotificationsServiceDeps = {}) {
        const notificationCtor = deps.notificationCtor ?? (typeof Notification !== 'undefined' ? Notification : undefined);

        this.deps = {
            driver: deps.driver ?? defaultDriver,
            fetchImpl: deps.fetchImpl ?? ((...args) => fetch(...args)),
            notificationCtor,
            getPermission: deps.getPermission ?? (() => notificationCtor?.permission ?? 'default'),
            requestPermissionImpl: deps.requestPermissionImpl
                ?? (async () => (notificationCtor?.requestPermission ? notificationCtor.requestPermission() : 'denied')),
            showNotification: deps.showNotification ?? (async (payload) => {
                const registration = await defaultSwRegistration();
                if (registration) {
                    await registration.showNotification(payload.title, {
                        body: payload.body,
                        tag: payload.tag,
                        data: payload.data,
                    });
                } else if (notificationCtor) {
                    new notificationCtor(payload.title, { body: payload.body, tag: payload.tag, data: payload.data });
                }
            }),
            swRegistration: deps.swRegistration ?? defaultSwRegistration,
            now: deps.now ?? (() => new Date()),
            todayIso: deps.todayIso ?? todayIsoDefault,
        };
    }

    isSupported(): boolean {
        return this.deps.notificationCtor !== undefined
            && typeof navigator !== 'undefined'
            && 'serviceWorker' in navigator
            && 'PushManager' in (typeof window !== 'undefined' ? window : globalThis);
    }

    getPermission(): NotificationPermission {
        return this.deps.getPermission();
    }

    async requestPermission(): Promise<NotificationPermission> {
        return this.deps.requestPermissionImpl();
    }

    async getPreferences(): Promise<NotificationPreferences> {
        const driver = await this.deps.driver();
        const rows = await driver.query<{ value: string }>(
            'SELECT value FROM settings WHERE key = ?',
            PREFERENCES_KEY,
        );
        if (rows.length === 0) return { ...DEFAULT_NOTIFICATION_PREFERENCES };

        try {
            const parsed = JSON.parse(rows[0].value) as Partial<NotificationPreferences>;
            return { ...DEFAULT_NOTIFICATION_PREFERENCES, ...parsed };
        } catch {
            return { ...DEFAULT_NOTIFICATION_PREFERENCES };
        }
    }

    async setPreferences(prefs: Partial<NotificationPreferences>): Promise<NotificationPreferences> {
        const current = await this.getPreferences();
        const merged: NotificationPreferences = { ...current, ...prefs };
        const driver = await this.deps.driver();
        await driver.execute(
            `INSERT INTO settings (key, value) VALUES (?, ?)
             ON CONFLICT(key) DO UPDATE SET value = excluded.value, updated_at = datetime('now')`,
            PREFERENCES_KEY,
            JSON.stringify(merged),
        );
        return merged;
    }

    async subscribePush(): Promise<PushSubscriptionPayload> {
        const registration = await this.deps.swRegistration();
        if (!registration) throw new Error('Service worker not registered');

        const vapidResponse = await this.deps.fetchImpl(`${API_URL}/api/notifications/vapid-public-key`);
        if (!vapidResponse.ok) throw new Error(`Failed to fetch VAPID key: HTTP ${vapidResponse.status}`);
        const { publicKey } = await vapidResponse.json() as { publicKey: string };

        const subscription = await registration.pushManager.subscribe({
            userVisibleOnly: true,
            applicationServerKey: urlBase64ToUint8Array(publicKey),
        });

        const json = subscription.toJSON() as PushSubscriptionPayload;
        const subscribeResponse = await this.deps.fetchImpl(`${API_URL}/api/notifications/subscribe`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(json),
        });
        if (!subscribeResponse.ok) throw new Error(`Failed to register subscription: HTTP ${subscribeResponse.status}`);
        return json;
    }

    async getSubscriptionEndpoint(): Promise<string | null> {
        const registration = await this.deps.swRegistration();
        const existing = await registration?.pushManager.getSubscription();
        return existing?.endpoint ?? null;
    }

    async unsubscribePush(): Promise<boolean> {
        const registration = await this.deps.swRegistration();
        const existing = await registration?.pushManager.getSubscription();
        if (!existing) return false;

        await this.deps.fetchImpl(`${API_URL}/api/notifications/subscribe`, {
            method: 'DELETE',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ endpoint: existing.endpoint }),
        });
        return existing.unsubscribe();
    }

    async runLocalChecks(): Promise<LocalCheckResult> {
        const result: LocalCheckResult = { shown: [], skipped: [] };

        if (this.deps.getPermission() !== 'granted') {
            result.skipped.push('permission-not-granted');
            return result;
        }

        const preferences = await this.getPreferences();
        const driver = await this.deps.driver();

        if (preferences.learning) {
            const srs = await this.buildSrsPayload(driver);
            if (srs) {
                await this.deps.showNotification(srs);
                result.shown.push(srs);
            }
        } else {
            result.skipped.push('learning-disabled');
        }

        if (preferences.health) {
            const nutrition = await this.buildNutritionPayloads(driver);
            for (const payload of nutrition) {
                await this.deps.showNotification(payload);
                result.shown.push(payload);
            }
        } else {
            result.skipped.push('health-disabled');
        }

        return result;
    }

    private async buildSrsPayload(driver: DbDriver): Promise<NotificationPayload | null> {
        const rows = await driver.query<{ due_count: number }>(`
            SELECT COUNT(c.id) AS due_count FROM cards c
            JOIN reviews r ON r.id = (
                SELECT id FROM reviews WHERE card_id = c.id ORDER BY created_at DESC LIMIT 1
            )
            WHERE datetime(r.due) <= datetime('now')
        `);
        const count = Number(rows[0]?.due_count ?? 0);
        if (count <= 0) return null;

        return {
            title: 'Vietnamese review ready',
            body: count === 1 ? '1 card is ready to review.' : `${count} cards are ready to review.`,
            tag: 'srs-due',
            data: { path: '/vietnamese/review', category: 'learning' },
        };
    }

    private async buildNutritionPayloads(driver: DbDriver): Promise<NotificationPayload[]> {
        const payloads: NotificationPayload[] = [];
        const now = this.deps.now();
        const hour = now.getHours();
        const date = this.deps.todayIso();

        for (const reminder of MEAL_REMINDERS) {
            if (hour < reminder.startHour || hour >= reminder.endHour) continue;

            const rows = await driver.query<{ c: number }>(
                'SELECT COUNT(*) AS c FROM nutrition_logs WHERE date = ? AND LOWER(meal_type) = LOWER(?)',
                date,
                reminder.meal,
            );

            if (Number(rows[0]?.c ?? 0) > 0) continue;

            payloads.push({
                title: `${reminder.meal} not logged yet`,
                body: `Tap to log what you ate for ${reminder.meal.toLowerCase()}.`,
                tag: `nutrition-missing-${reminder.meal.toLowerCase()}-${date}`,
                data: {
                    path: `/health/food-entry/${date}/${reminder.meal}`,
                    category: 'health',
                },
            });
        }

        return payloads;
    }
}

export const NOTIFICATION_CATEGORY_LABELS: Record<NotificationCategory, string> = {
    learning: 'Vietnamese — cards due',
    health: 'Health — missing meal reminders',
    social: 'Social — outreach reminders',
};

export const notificationsService = new NotificationsService();
export { NOTIFICATION_CATEGORIES };
